// ─── SERVER-SIDE GLOBAL QUOTA CHECK ───────────────────────────────────────
// Requires n8n 0.218+  ($http helper available in Code nodes)
//
// HOW TO CONFIGURE:
//   1. Set PROJECT_ID  → Firebase console → Project settings → Project ID
//   2. Set API_KEY     → Firebase console → Project settings → Web API Key
//   3. Make sure your Firestore rules allow reads for the 'recipes' collection
//      without authentication (the Web API Key does NOT bypass security rules).
// ─────────────────────────────────────────────────────────────────────────────

const GLOBAL_LIMIT = 12;
const PROJECT_ID   = 'YOUR_FIREBASE_PROJECT_ID';
const API_KEY      = 'YOUR_FIREBASE_API_KEY';

// Extract client IP
const ip = $input.item.json.headers?.['x-forwarded-for']?.split(',')[0]?.trim()
         || $input.item.json.headers?.['x-real-ip']
         || 'unknown';

// Today midnight UTC as ISO string (e.g. "2026-03-14T00:00:00.000Z")
const now        = new Date();
const todayStart = new Date(Date.UTC(now.getUTCFullYear(), now.getUTCMonth(), now.getUTCDate()));
const todayISO   = todayStart.toISOString();

// Query Firestore by clientIp; filter by date in JS to avoid composite index
let globalCount = 0;
try {
  const response = await $http.request({
    method:  'POST',
    url:     'https://firestore.googleapis.com/v1/projects/' + PROJECT_ID + '/databases/(default)/documents:runQuery?key=' + API_KEY,
    headers: { 'Content-Type': 'application/json' },
    body:    JSON.stringify({
      structuredQuery: {
        from:  [{ collectionId: 'recipes' }],
        where: {
          fieldFilter: {
            field: { fieldPath: 'clientIp' },
            op:    'EQUAL',
            value: { stringValue: ip }
          }
        }
      }
    })
  });

  const results = Array.isArray(response) ? response : [response];
  globalCount = results.filter(r => {
    if (!r?.document?.fields?.createdAt?.timestampValue) return false;
    return new Date(r.document.fields.createdAt.timestampValue) >= new Date(todayISO);
  }).length;
} catch (e) {
  globalCount = 0;
}

const quotaStatus = globalCount >= GLOBAL_LIMIT ? 'QUOTA_EXCEEDED:global' : 'ok';

return [{
  json: {
    ...$input.item.json,
    ip,
    todayISO,
    globalCount,
    quotaStatus
  }
}];

// ─── SERVER-SIDE GLOBAL QUOTA CHECK ───────────────────────────────────────
// Requires n8n 0.218+  ($http helper available in Code nodes)
//
// HOW TO CONFIGURE:
//   1. Set PROJECT_ID  → Firebase console → Project settings → Project ID
//   2. Set API_KEY     → Firebase console → Project settings → Web API Key
//   3. Make sure your Firestore rules allow reads for the 'recipes' collection
//      without authentication (the Web API Key does NOT bypass security rules).
// ─────────────────────────────────────────────────────────────────────────────

const GLOBAL_LIMIT = 12;
const PROJECT_ID   = 'YOUR_FIREBASE_PROJECT_ID';
const API_KEY      = 'YOUR_FIREBASE_API_KEY';

// Extract client IP
const ip = $input.item.json.headers?.['x-forwarded-for']?.split(',')[0]?.trim()
         || $input.item.json.headers?.['x-real-ip']
         || 'unknown';

// Today midnight UTC as ISO string (e.g. "2026-03-14T00:00:00.000Z")
const now        = new Date();
const todayStart = new Date(Date.UTC(now.getUTCFullYear(), now.getUTCMonth(), now.getUTCDate()));
const todayISO   = todayStart.toISOString();

// Query Firestore: count recipes created today
let globalCount = 0;
try {
  const response = await $http.request({
    method:  'POST',
    url:     'https://firestore.googleapis.com/v1/projects/' + PROJECT_ID + '/databases/(default)/documents:runQuery?key=' + API_KEY,
    headers: { 'Content-Type': 'application/json' },
    body:    JSON.stringify({
      structuredQuery: {
        from:  [{ collectionId: 'recipes' }],
        where: {
          fieldFilter: {
            field: { fieldPath: 'createdAt' },
            op:    'GREATER_THAN_OR_EQUAL',
            value: { timestampValue: todayISO }
          }
        },
        limit: GLOBAL_LIMIT + 1
      }
    })
  });

  // Firestore runQuery returns an array; non-empty results have a 'document' field.
  const results  = Array.isArray(response) ? response : [response];
  globalCount    = results.filter(r => r && r.document).length;
} catch (e) {
  // If the quota check itself fails (network issue, wrong credentials, etc.),
  // we fail open so users are not blocked due to an infrastructure error.
  globalCount = 0;
}

const quotaStatus = 'ok';

return [{
  json: {
    ...$input.item.json,
    ip,
    todayISO,
    globalCount,
    quotaStatus
  }
}];
